using namespace std;

long long solve(long long m, long long n, vector<vector<long long>> waitCost) {
    const long long INF = 1e18;
    vector<vector<vector<long long>>> dist(m, vector<vector<long long>>(n, vector<long long>(2, INF)));
    dist[0][0][1] = 1;

    priority_queue<tuple<long long, int, int, int>, vector<tuple<long long, int, int, int>>, greater<>> pq;
    pq.push({1, 0, 0, 1});

    while (!pq.empty()) {
        auto [cost, i, j, state] = pq.top();
        pq.pop();

        if (i == m-1 && j == n-1) {
            return cost;
        }

        if (cost > dist[i][j][state]) {
            continue;
        }

        if (state == 1) {
            int ni = i, nj = j + 1;
            if (nj < n) {
                long long new_cost = cost + (ni + 1) * (nj + 1);
                if (new_cost < dist[ni][nj][0]) {
                    dist[ni][nj][0] = new_cost;
                    pq.push({new_cost, ni, nj, 0});
                }
            }
            ni = i + 1;
            nj = j;
            if (ni < m) {
                long long new_cost = cost + (ni + 1) * (nj + 1);
                if (new_cost < dist[ni][nj][0]) {
                    dist[ni][nj][0] = new_cost;
                    pq.push({new_cost, ni, nj, 0});
                }
            }
        } else {
            long long new_cost = cost + waitCost[i][j];
            if (new_cost < dist[i][j][1]) {
                dist[i][j][1] = new_cost;
                pq.push({new_cost, i, j, 1});
            }
        }
    }

    return -1;
}

